INSERT INTO `chat_messages` VALUES
('1','1','0',NULL,'bot','Xin chào! Tôi là trợ lý ảo của Aurora Hotel Plaza. Tôi có thể giúp gì cho bạn về đặt phòng, dịch vụ hoặc thông tin khách sạn?','text','0',NULL,'1','2026-04-02 20:16:50','2026-04-02 20:16:50'),
('2','2','0',NULL,'bot','Xin chào! Tôi là trợ lý ảo của Aurora Hotel Plaza. Tôi có thể giúp gì cho bạn về đặt phòng, dịch vụ hoặc thông tin khách sạn?','text','0',NULL,'1','2026-04-02 20:17:19','2026-04-02 20:17:19'),
('3','2','0','guest_2de57889aa5df1b47799e4f1251f9174','customer','hé lô','text','0',NULL,'1','2026-04-06 17:29:47','2026-04-02 20:17:22'),
('4','2','0',NULL,'bot','Xin chào! Tôi là Aurora - Trợ lý ảo của Aurora Hotel Plaza. Rất vui được gặp bạn! ???? Có điều gì tôi có thể giúp bạn không?','text','0',NULL,'0',NULL,'2026-04-02 20:17:23'),
('5','1','0','guest_5a7a5ea46f8027fb753d9d4bcdbbdfbf','customer','Hi Aurora bên mình coa cho thuê căn hộ 3-5 ngày hoặc 1-3 tháng loại ngắn hạn ko','text','0',NULL,'1','2026-04-06 17:29:51','2026-04-02 20:17:32'),
('6','1','0',NULL,'bot','Dựa trên thông tin về các loại phòng tại Aurora Hotel Plaza, chúng tôi không cung cấp dịch vụ cho thuê căn hộ ngắn hạn (3-5 ngày hoặc 1-3 tháng). Tuy nhiên, chúng tôi có nhiều loại phòng nghỉ cao cấp như:\n\n- **Deluxe**: Phù hợp cho 2 người, 1 giường đôi lớn (1m8x2m)\n- **Premium Deluxe Double**: Phù hợp cho 2 người, 1 giường đôi lớn (1m8xx2m)\n- **Premium Deluxe Twin**: Phù hợp cho 2 người, 2 giường đơn (1m4x2m)\n- **Aurora Studio**: Phù hợp cho 3 người, 1 giường siêu lớn (2mx2m)\n- **Studio Apartment**: Phù hợp cho 2 người, 1 Giường Queen\n- **Modern Studio**: Phù hợp cho 2 người, 1 Giường King\n- **Indochine Studio**: Phù hợp cho 2 người, 1 Giường Queen\n- **Premium Apartment**: Phù hợp cho 3 người, 1 Giường King + Sofa bed\n- **Modern Premium**: Phù hợp cho 3 người, 1 Giường King + Sofa bed\n- **Classical Premium**: Phù hợp cho 3 người, 1 Giường King + Sofa bed\n- **Family Apartment**: Phù hợp cho 5 người, 1 King + 2 Đơn\n- **Indochine Family**: Phù hợp cho 5 người, 1 King + 2 Đơn\n- **Classical Family**: Phù hợp cho 5 người, 1 King + 2 Đơn\n\nNếu bạn cần hỗ trợ đặt phòng hoặc tìm hiểu thêm về các gói dịch vụ, vui lòng cho tôi biết!','text','0',NULL,'1','2026-04-02 20:17:41','2026-04-02 20:17:37'),
('7','1','0','guest_5a7a5ea46f8027fb753d9d4bcdbbdfbf','customer','Hi','text','0',NULL,'1','2026-04-06 17:29:51','2026-04-02 20:18:20'),
('8','1','0',NULL,'bot','Xin chào! Rất vui được gặp lại bạn. Nếu bạn cần hỗ trợ bất kỳ thông tin nào về phòng nghỉ, dịch vụ hoặc chương trình khuyến mãi tại Aurora Hotel Plaza, đừng ngần ngại hỏi tôi nhé! ????','text','0',NULL,'0',NULL,'2026-04-02 20:18:21'),
