('2','LE3004BUFFET','Voucher Lễ 30/4 - Tặng 2 vé buffet','National Holiday 30/4 – 2 Free Buffet Tickets',NULL,'Special National Holiday offer: Book a stay and receive 2 complimentary buffet tickets.','fixed_amount','0.00','2000000.00',NULL,NULL,'1','0','all','2026-03-04 16:27:35','2026-05-02 00:00:00','active',NULL,'2026-02-28 16:50:58','2026-03-04 16:27:35'),
