INSERT INTO `service_packages` VALUES
('1','1','Gói Cơ bản','Basic Package','wedding-basic','Gói tiệc cưới cơ bản cho 200-300 khách.','Basic wedding package for 200–300 guests.','Sảnh tiệc 200-300 khách,Trang trí cơ bản,Menu 8 món,Âm thanh ánh sáng,Bàn ghế tiêu chuẩn,Backdrop sân khấu','Banquet hall for 200-300 guests,Basic decoration,8-course menu,Sound & Lighting,Standard furniture,Stage backdrop','15000000.00','VND','VND','0','1','1','2025-11-19 01:34:50','2026-03-04 17:13:22'),
('2','1','Gói Tiêu chuẩn','Standard Package','wedding-standard','Gói tiệc cưới tiêu chuẩn cho 400-500 khách.','Standard wedding package for 400–500 guests.','Sảnh tiệc 400-500 khách,Trang trí theo chủ đề,Menu 10 món + tráng miệng,Âm thanh ánh sáng cao cấp,Bàn ghế VIP,Backdrop + Cổng hoa,MC chuyên nghiệp,Nhiếp ảnh cơ bản','Banquet hall for 400-500 guests,Themed decoration,10-course menu + dessert,Premium sound & lighting,VIP furniture,Backdrop + Flower arch,Professional MC,Basic photography','25000000.00','VND','VND','1','1','2','2025-11-19 01:34:50','2026-03-04 17:13:22'),
('3','1','Gói VIP','VIP Package','wedding-vip','Gói tiệc cưới VIP cho 600-800 khách.','VIP wedding package for 600–800 guests.','Sảnh tiệc 600-800 khách,Trang trí sang trọng,Menu 12 món + buffet tráng miệng,Âm thanh ánh sáng 3D,Bàn ghế VIP cao cấp,Backdrop + Cổng hoa + Sân khấu,MC + Ban nhạc,Nhiếp ảnh + Quay phim,Trang điểm cô dâu,Xe hoa','Banquet hall for 600-800 guests,Luxury decoration,12-course menu + dessert buffet,3D sound & lighting,Premium VIP furniture,Backdrop + Flower arch + Stage,MC + Live band,Photography + Videography,Bridal makeup,Wedding car','40000000.00','VND','VND','1','1','3','2025-11-19 01:34:50','2026-03-04 17:13:22'),
('4','3','Buffet Sáng','Breakfast Buffet','restaurant-breakfast','Buffet sáng với hơn 50 món Á - Âu.','Breakfast buffet with over 50 Asian and European dishes.','Hơn 50 món ăn,Phở - Bún - Cháo,Bánh mì - Xúc xích,Trứng các loại,Hoa quả tươi,Nước ép - Cà phê,Thời gian: 6h-10h','Over 50 dishes,Pho - Noodles - Porridge,Bread - Sausages,Various eggs,Fresh fruits,Juice - Coffee,Time: 6am - 10am','200000.00','VND/người','VND/person','0','1','1','2025-11-19 01:34:50','2026-03-04 17:13:22'),
('5','3','Buffet Trưa/Tối','Lunch / Dinner Buffet','restaurant-lunch-dinner','Buffet trưa hoặc tối với hơn 100 món.','Lunch or dinner buffet with over 100 dishes.','Hơn 100 món ăn,Hải sản tươi sống,Sushi Nhật Bản,BBQ Hàn Quốc,Món Việt truyền thống,Món Âu cao cấp,Tráng miệng đa dạng,Nước uống không giới hạn','Over 100 dishes,Fresh seafood,Japanese Sushi,Korean BBQ,Traditional Vietnamese dishes,Premium Western dishes,Various desserts,Unlimited drinks','350000.00','VND/người','VND/person','1','1','2','2025-11-19 01:34:50','2026-03-04 17:13:22'),
('6','3','Set Menu VIP','VIP Set Menu','restaurant-set-menu','Set menu cao cấp phục vụ riêng.','Premium set menu with private dining service.','Khai vị cao cấp,Súp đặc biệt,Món chính (Bò/Hải sản),Món phụ,Tráng miệng,Rượu vang,Phục vụ riêng tư,Không gian VIP','Premium appetizer,Special soup,Main course (Beef/Seafood),Side dish,Dessert,Wine,Private service,VIP space','800000.00','VND/người','VND/person','1','1','3','2025-11-19 01:34:50','2026-03-04 17:13:22'),
('7','2','Gói Nửa ngày','Half-Day Package','conference-half-day','Gói hội nghị nửa ngày (4 giờ) phù hợp cho 50-100 người.','Half-day conference package (4 hours) for 50–100 attendees.','Phòng họp 50-100 người,Projector + Màn hình,Micro không dây,WiFi miễn phí,Coffee break 1 lần,Bảng Flipchart','Meeting room for 50-100 people,Projector + Screen,Wireless microphone,Free WiFi,1 Coffee break,Flipchart','6000000.00','VND/4 giờ','VND/4 hours','0','1','1','2025-11-19 01:34:50','2026-03-04 17:13:22'),
('8','2','Gói Cả ngày','Full-Day Package','conference-full-day','Gói hội nghị cả ngày (8 giờ) cho 100-200 người.','Full-day conference package (8 hours) for 100–200 attendees.','Phòng họp 100-200 người,Màn hình LED lớn,Hệ thống âm thanh cao cấp,WiFi tốc độ cao,Coffee break 2 lần,Buffet trưa,Bảng Flipchart + Bút,Hỗ trợ kỹ thuật','Meeting room for 100-200 people,Large LED screen,Premium audio system,High-speed WiFi,2 Coffee breaks,Lunch buffet,Flipchart + Pens,Technical support','9000000.00','VND/8 giờ','VND/8 hours','1','1','2','2025-11-19 01:34:50','2026-03-04 17:13:22'),
('9','2','Gói VIP','VIP Package','conference-vip','Gói hội nghị VIP cho 200-300 người.','VIP conference package for 200–300 attendees.','Phòng hội nghị 200-300 người,Màn hình LED 3D,Âm thanh chuyên nghiệp,WiFi doanh nghiệp,Coffee break 3 lần,Buffet trưa + tối,Phòng VIP cho ban tổ chức,Ghi hình chuyên nghiệp,Hỗ trợ kỹ thuật 24/7','Conference room for 200-300 people,3D LED screen,Professional audio,Enterprise WiFi,3 Coffee breaks,Lunch + Dinner buffet,VIP room for organizers,Professional recording,24/7 Technical support','15000000.00','VND/ngày','VND/day','1','1','3','2025-11-19 01:34:50','2026-03-04 17:13:22'),
('10','4','Studio 20m²','Studio 20m²','office-studio','Văn phòng Studio cho 2-3 người.','Studio office for 2–3 people.','Diện tích 20m²,2-3 người,Bàn làm việc,Ghế ergonomic,Tủ tài liệu,Điều hòa,WiFi 1Gbps','Area 20m²,2-3 people,Work desk,Ergonomic chair,Filing cabinet,Air conditioning,1Gbps WiFi','3000000.00','VND/tháng','VND/month','0','1','1','2025-11-19 01:34:50','2026-03-04 17:13:22'),
('11','4','Standard 40m²','Standard 40m²','office-standard','Văn phòng Standard cho 5-8 người.','Standard office space for 5–8 people.','Diện tích 40m²,5-8 người,Bàn làm việc,Ghế ergonomic,Tủ tài liệu,Điều hòa,WiFi 1Gbps,Phòng họp chung','Area 40m²,5-8 people,Work desk,Ergonomic chair,Filing cabinet,Air conditioning,1Gbps WiFi,Shared meeting room','5500000.00','VND/tháng','VND/month','1','1','2','2025-11-19 01:34:50','2026-03-04 17:13:22'),
('12','4','Premium 80m²','Premium 80m²','office-premium','Văn phòng Premium cho 10-15 người.','Premium office space for 10–15 people.','Diện tích 80m²,10-15 người,Bàn làm việc cao cấp,Ghế ergonomic,Tủ tài liệu,Điều hòa trung tâm,WiFi 1Gbps,Phòng họp riêng,Khu pantry riêng','Area 80m²,10-15 people,Premium work desk,Ergonomic chair,Filing cabinet,Central air conditioning,1Gbps WiFi,Private meeting room,Private pantry area','8000000.00','VND/tháng','VND/month','1','1','3','2025-11-19 01:34:50','2026-03-04 17:13:22');
INSERT INTO `services` VALUES
('1','Tổ chức tiệc cưới','Wedding Services','wedding-service','event','Aurora Hotel Plaza tự hào là địa điểm tổ chức tiệc cưới hàng đầu tại Đồng Nai với sảnh tiệc sang trọng 500m², sức chứa lên đến 800 khách. Đội ngũ chuyên nghiệp với hơn 500 tiệc cưới thành công.','Aurora Hotel Plaza is proud to be the leading wedding venue in Dong Nai with a luxurious 500m² banquet hall, capacity for up to 800 guests. Our experienced team has successfully organized over 500 weddings.','Sảnh tiệc 500m², sức chứa 800 khách, dịch vụ trọn gói','Elegant wedding venues and planning for up to 800 guests','celebration','500000.00','VND','assets/img/post/wedding/tiec-cuoi-tai-aurora-1.jpg',NULL,'1','1','1','2025-11-19 01:34:50','2026-03-06 16:07:07'),
('2','Tổ chức hội nghị','Conference & Events','conference-service','event','Phòng hội nghị hiện đại với 5 phòng họp đa năng, sức chứa từ 20-300 người. Trang bị đầy đủ thiết bị hiện đại, WiFi tốc độ cao, dịch vụ coffee break và buffet.','Modern conference center with 5 multi-purpose meeting rooms, capacity from 20 to 300 people. Fully equipped with state-of-the-art technology, high-speed WiFi, coffee break and buffet services.','Phòng họp hiện đại, thiết bị đầy đủ, WiFi tốc độ cao','Modern conference rooms, full equipment, high-speed WiFi','meeting_room','5000000.00','VND','assets/img/service/meet/hoi-nghi-aurora-5.jpg',NULL,'1','1','2','2025-11-19 01:34:50','2026-03-06 15:59:46'),
('3','Nhà hàng Aurora','Aurora Restaurant','aurora-restaurant','restaurant','Nhà hàng sang trọng với sức chứa 200 khách, view thành phố tuyệt đẹp. Buffet đa dạng hơn 100 món Á-Âu: hải sản tươi sống, sushi Nhật Bản, BBQ Hàn Quốc, món Việt truyền thống.','Luxurious restaurant with capacity for 200 guests and stunning city views. Diverse buffet with over 100 Asian and European dishes: fresh seafood, Japanese sushi, Korean BBQ, traditional Vietnamese cuisine.','Buffet 100+ món Á-Âu, view đẹp, đầu bếp 5 sao','Buffet with 100+ Asian & European dishes, beautiful views, 5-star chef','restaurant','350000.00','VND','assets/img/restaurant/nha-hang-aurora-hotel-2.jpg',NULL,'1','1','3','2025-11-19 01:34:50','2026-03-06 15:59:46'),
('4','Văn phòng cho thuê','Office Rental','office-rental','other','Văn phòng hiện đại với 3 loại: Studio 20m², Standard 40m², Premium 80m². Đầy đủ nội thất, WiFi 1Gbps, phòng họp chung, bảo vệ 24/7.','Modern offices available in 3 types: Studio 20m², Standard 40m², Premium 80m². Fully furnished, 1Gbps WiFi, shared meeting rooms, 24/7 security.','Văn phòng đầy đủ nội thất, WiFi 1Gbps, tiện ích đầy đủ','Fully furnished offices, 1Gbps WiFi, full business amenities','business_center','8000000.00','VND','assets/img/service/office/van-phong-cho-thue-aurora-2.jpg',NULL,'1','1','4','2025-11-19 01:34:50','2026-03-06 15:59:46'),
('5','Rooftop Bar','Rooftop Bar','rooftop-bar','restaurant','Quầy bar tầng thượng với view 360 độ thành phố Biên Hòa. Không gian sang trọng, âm nhạc sống mỗi tối thứ 6-7. Menu cocktail đa dạng.','Rooftop bar with 360° panoramic views of Bien Hoa city. Luxurious atmosphere with live music every Friday and Saturday. Extensive cocktail menu.','Bar tầng thượng, view 360°, cocktail đa dạng, nhạc sống','Rooftop bar, 360° city view, cocktails, live music','local_bar','150000.00','VND','assets/img/post/restaurant/rooftop-bar-1.jpg',NULL,'1','1','5','2025-11-19 01:34:50','2026-03-06 15:59:46'),
('6','Dịch vụ phòng 24/7','Room Service 24/7','room-service-24-7','room_service','Dịch vụ phòng hoạt động 24/7 với thực đơn đa dạng hơn 50 món.','24/7 in-room dining service with a diverse menu of over 50 dishes available at any hour.','Gọi món ăn, đồ uống phục vụ tận phòng 24/7','Order food and drinks delivered to your room 24/7','room_service','0.00','VND',NULL,NULL,'1','0','6','2025-11-19 01:34:50','2026-03-06 15:59:46'),
('7','Dọn phòng hàng ngày','Daily Housekeeping','daily-housekeeping','room_service','Dịch vụ dọn phòng hàng ngày với đội ngũ chuyên nghiệp.','Daily housekeeping service by our professional team, ensuring a clean, comfortable room every day.','Dọn dẹp và thay đổi khăn giường mỗi ngày','Professional daily cleaning with fresh linen change','cleaning_services','0.00','VND',NULL,NULL,'1','0','7','2025-11-19 01:34:50','2026-03-06 15:59:46'),
('8','Giặt ủi cao cấp','Premium Laundry','laundry-service','laundry','Dịch vụ giặt ủi chuyên nghiệp với máy móc hiện đại.','Professional laundry service using modern machines. We pick up and deliver clean clothes directly to your room.','Giặt ủi quần áo chuyên nghiệp, giao nhận tận phòng','Professional laundry, pickup and delivery to your room','local_laundry_service','50000.00','VND',NULL,NULL,'1','0','8','2025-11-19 01:34:50','2026-03-06 15:59:46'),
('9','Massage trị liệu','Therapeutic Massage','therapeutic-massage','spa','Massage trị liệu chuyên sâu giúp giảm căng thẳng, đau nhức cơ bắp.','Specialized therapeutic massage to relieve stress and muscle pain. Our skilled therapists use natural essential oils to provide the most relaxing experience.','Massage thư giãn toàn thân với tinh dầu thiên nhiên','Relaxing full-body massage with natural essential oils','spa','500000.00','VND',NULL,NULL,'1','1','9','2025-11-19 01:34:50','2026-03-06 15:59:46'),
('10','Sauna & Jacuzzi','Sauna & Jacuzzi','sauna-jacuzzi','spa','Phòng xông hơi khô và bồn tắm massage cao cấp.','Premium dry sauna room and high-end Jacuzzi massage bathtub. Perfect for unwinding after a long day.','Xông hơi khô và bồn tắm nước nóng massage','Dry sauna and hot tub massage session','hot_tub','300000.00','VNĐ/45 phút',NULL,NULL,'1','0','10','2025-11-19 01:34:50','2026-03-04 16:40:58'),
('11','Hồ bơi & Gym','Swimming Pool & Gym','pool-gym','other','Hồ bơi ngoài trời 25m x 12m và phòng gym 200m² với trang thiết bị Technogym.','Outdoor swimming pool 25m × 12m and 200m² gym equipped with Technogym equipment. Complimentary for all hotel guests.','Hồ bơi ngoài trời và phòng gym hiện đại miễn phí','Outdoor pool and modern gym — free for guests','pool','0.00','Miễn phí',NULL,NULL,'1','1','11','2025-11-19 01:34:50','2026-03-04 16:40:58'),
('12','Đưa đón sân bay','Airport Transfer','airport-transfer','transport','Dịch vụ đưa đón sân bay Tân Sơn Nhất bằng xe sang.','Premium airport transfer service to and from Tan Son Nhat International Airport in a luxury vehicle. Book in advance for guaranteed pickup.','Xe đưa đón sân bay Tân Sơn Nhất tiện lợi, an toàn','Safe and comfortable airport transfer to/from Tan Son Nhat','local_taxi','500000.00','VND',NULL,NULL,'1','0','12','2025-11-19 01:34:50','2026-03-06 15:59:46'),
('13','Thuê xe tự lái','Self-Drive Car Rental','car-rental','transport','Cho thuê xe tự lái đa dạng dòng xe 4-7 chỗ.','Self-drive car rental with a variety of 4–7 seat vehicles. All cars are new, fully insured, available for short or long-term rental.','Thuê xe tự lái 4-7 chỗ, xe mới, bảo hiểm đầy đủ','4–7 seat self-drive car rental, new vehicles, full insurance','directions_car','800000.00','VND',NULL,NULL,'1','0','13','2025-11-19 01:34:50','2026-03-06 15:59:46'),
('14','Trông trẻ','Babysitting','babysitting','other','Dịch vụ trông trẻ chuyên nghiệp, an toàn cho trẻ từ 6 tháng đến 12 tuổi.','Professional babysitting service, safe for children from 6 months to 12 years old. All caregivers are trained and supervised by camera.','Dịch vụ trông trẻ an toàn, chuyên nghiệp, giám sát camera','Professional, safe childcare with camera monitoring','child_care','100000.00','VND',NULL,NULL,'1','0','14','2025-11-19 01:34:50','2026-03-06 15:59:46');
